472	func (t *teeWriter) Write(b []byte) (int, error) {
473		t.mu.Lock()
474		defer t.mu.Unlock()
475	
476		n, err := t.base.Write(b)
477		// Accumulate; emit one Event per newline-terminated chunk.
478		if n > 0 {
479			t.buf = append(t.buf, b[:n]...)
480		}
481		var lines [][]byte
482		for {
483			i := indexByte(t.buf, '\n')
484			if i < 0 {
485				break
486			}
487			line := append([]byte(nil), t.buf[:i]...)
488			t.buf = t.buf[i+1:]
489			lines = append(lines, line)
490		}
491		for _, line := range lines {
492			t.dispatch(line)
493		}
494		return n, err
495	}
