281	// tick performs one probe cycle and returns true on a successful reach
282	// (server replied to register or to a register that was already in place).
283	func (p *Probe) tick(ctx context.Context) bool {
284		addr := ""
285		if p.cfg.AddrFunc != nil {
286			addr = p.cfg.AddrFunc()
287		}
288		if addr == "" {
289			// No server configured. Drive Connected→NotConnected if we used to
290			// be connected; otherwise no-op.
291			p.markDisconnected("no_addr")
292			return false
293		}
294	
295		// Already connected: cheap reachability check by hitting register again
296		// is overkill; we just trust the connection and let event POSTs surface
297		// failures via the failure-counter (markDisconnected is called from
298		// postEvent when the POST fails). This keeps probe traffic minimal.
299		if p.Connected() {
300			return true
301		}
302	
303		// NotConnected: attempt to register.
304		workerID, err := p.postRegister(ctx, addr)
305		if err != nil {
306			fmt.Fprintf(p.cfg.Logger, "workerprobe: register failed: %v\n", err)
307			return false
308		}
309		p.markConnected(workerID)
310	
311		// Drain the ring buffer via backfill (best-effort).
312		p.flushBackfill(ctx, addr, workerID)
313		return true
314	}
