333	func (p *Probe) flushBackfill(ctx context.Context, addr, workerID string) {
334		p.mu.Lock()
335		if len(p.buf) == 0 && !p.dropped {
336			p.mu.Unlock()
337			return
338		}
339		events := make([]Event, len(p.buf))
340		copy(events, p.buf)
341		dropped := p.dropped
342		p.mu.Unlock()
343	
344		if err := p.postBackfill(ctx, addr, workerID, events, dropped); err != nil {
345			fmt.Fprintf(p.cfg.Logger, "workerprobe: backfill failed: %v\n", err)
346			return
347		}
348	
349		// Success: clear the ring buffer.
350		p.mu.Lock()
351		p.buf = p.buf[:0]
352		p.dropped = false
353		p.mu.Unlock()
354	}
