401		req.Header.Set("Content-Type", "application/json")
402		resp, err := p.cfg.HTTPClient.Do(req)
403		if err != nil {
404			fmt.Fprintf(p.cfg.Logger, "workerprobe: event POST failed: %v\n", err)
405			// Re-buffer the event so a future backfill catches it; flip state.
406			p.mu.Lock()
