31	}
32	
33	// Scanner discovers live ddx worker processes on the host.
34	type Scanner interface {
35		Scan(ctx context.Context) ([]LiveWorker, error)
36	}
37	
38	// New returns the platform-appropriate Scanner. On Linux this reads /proc.
39	// On other platforms it returns an empty list; the caller's tests and the
40	// --all-projects escape hatch remain meaningful regardless.
41	func New() Scanner {
42		return newSystemScanner()
43	}
44	
45	// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
46	// total) embedded in argv strings or worktree paths.
47	var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)
48	
49	// executionWorktreePattern matches the conventional execute-bead worktree
50	// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
51	// in a path. The directory name is enough to identify the worktree even when
52	// the surrounding path is unconventional.
53	var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)
54	
55	// InferBead extracts a bead ID and execution worktree path from the worker's
56	// command line and current working directory. It returns the longest worktree
57	// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
58	// the inline worker has chdir'd into the isolated worktree), and the first
59	// bead ID matched in either the command line or the worktree path.
60	//
61	// Either return value may be empty when no signal is present, which is the
62	// expected case for a long-running `ddx work` drain that has not yet started
63	// a specific bead.
64	func InferBead(cmdline, cwd string) (beadID, worktree string) {
65		worktree = extractWorktreePath(cwd)
66		if worktree == "" {
67			worktree = extractWorktreePath(cmdline)
68		}
69	
70		if m := beadIDPattern.FindString(worktree); m != "" {
71			beadID = m
72		}
73		if beadID == "" {
74			if m := beadIDPattern.FindString(cmdline); m != "" {
75				beadID = m
76			}
77		}
78		if beadID == "" {
79			if m := beadIDPattern.FindString(cwd); m != "" {
80				beadID = m
81			}
82		}
83		return beadID, worktree
84	}
85	
86	func extractWorktreePath(s string) string {
87		if s == "" {
88			return ""
89		}
90		if !strings.Contains(s, ".execute-bead-wt-") {
91			return ""
92		}
93		matches := executionWorktreePattern.FindStringIndex(s)
94		if matches == nil {
95			return ""
96		}
97		end := matches[1]
98		for end < len(s) {
99			r := s[end]
100			if r == ' ' || r == '\x00' || r == '\t' {
101				break
102			}
103			end++
104		}
105		return s[:end]
106	}
